  // Steps
  'step.design': { en: 'Design', zh: '设计', es: 'Diseñar', fr: 'Concevoir', de: 'Entwerfen', ja: 'デザイン', ko: '디자인', pt: 'Projetar', ar: 'تصميم', hi: 'डिज़ाइन', ru: 'Дизайн', it: 'Progetta' },
  'step.design.desc': { en: 'Build your survey with our intuitive drag-and-drop builder — or let AI do it.', zh: '使用直观的拖放构建器创建问卷——或让AI来做。', es: 'Construye tu encuesta con nuestro constructor intuitivo — o deja que la IA lo haga.', fr: 'Construisez votre sondage avec notre constructeur intuitif — ou laissez l\'IA le faire.', de: 'Erstellen Sie Ihre Umfrage mit unserem Drag-and-Drop-Builder — oder lassen Sie KI es tun.', ja: '直感的なビルダーでアンケートを作成 — またはAIにおまかせ。', ko: '직관적인 빌더로 설문조사를 만들거나 AI에게 맡기세요.', pt: 'Crie sua pesquisa com nosso construtor intuitivo — ou deixe a IA fazer.', ar: 'ابنِ استطلاعك باستخدام منشئنا البديهي — أو دع الذكاء الاصطناعي يفعل ذلك.', hi: 'हमारे सहज बिल्डर से सर्वेक्षण बनाएं — या AI को करने दें।', ru: 'Создайте опрос с помощью нашего конструктора — или пусть ИИ сделает это.', it: 'Crea il sondaggio con il nostro builder intuitivo — o lascia fare all\'IA.' },
  'step.distribute': { en: 'Distribute', zh: '分发', es: 'Distribuir', fr: 'Distribuer', de: 'Verteilen', ja: '配布', ko: '배포', pt: 'Distribuir', ar: 'توزيع', hi: 'वितरित करें', ru: 'Распространение', it: 'Distribuisci' },
  'step.distribute.desc': { en: 'Share via link or survey code. Works on any device.', zh: '通过链接或调查码分享，适用于任何设备。', es: 'Comparte por enlace o código. Funciona en cualquier dispositivo.', fr: 'Partagez par lien ou code. Fonctionne sur tout appareil.', de: 'Teilen per Link oder Code. Funktioniert auf jedem Gerät.', ja: 'リンクまたはコードで共有。どのデバイスでも。', ko: '링크 또는 코드로 공유. 모든 기기에서 작동.', pt: 'Compartilhe por link ou código. Funciona em qualquer dispositivo.', ar: 'شارك عبر رابط أو رمز. يعمل على أي جهاز.', hi: 'लिंक या कोड से साझा करें। किसी भी डिवाइस पर काम करता है।', ru: 'Поделитесь ссылкой или кодом. Работает на любом устройстве.', it: 'Condividi tramite link o codice. Funziona su qualsiasi dispositivo.' },
  'step.analyze': { en: 'Analyze', zh: '分析', es: 'Analizar', fr: 'Analyser', de: 'Analysieren', ja: '分析', ko: '분석', pt: 'Analisar', ar: 'تحليل', hi: 'विश्लेषण', ru: 'Анализ', it: 'Analizza' },
  'step.analyze.desc': { en: 'View real-time analytics and export your data.', zh: '查看实时分析并导出数据。', es: 'Ve analíticas en tiempo real y exporta tus datos.', fr: 'Consultez les analyses en temps réel et exportez vos données.', de: 'Sehen Sie Echtzeit-Analysen und exportieren Sie Ihre Daten.', ja: 'リアルタイム分析を確認し、データをエクスポート。', ko: '실시간 분석을 보고 데이터를 내보내세요.', pt: 'Veja análises em tempo real e exporte seus dados.', ar: 'اعرض التحليلات في الوقت الفعلي وصدّر بياناتك.', hi: 'रीयल-टाइम एनालिटिक्स देखें और डेटा निर्यात करें।', ru: 'Смотрите аналитику в реальном времени и экспортируйте данные.', it: 'Visualizza analisi in tempo reale ed esporta i tuoi dati.' },

