  'participantLibrary.title': { en: 'Participant Library', zh: '参与者库', es: 'Biblioteca de Participantes', fr: 'Bibliothèque de Participants', de: 'Teilnehmerbibliothek', ja: '参加者ライブラリ', ko: '참여자 라이브러리', pt: 'Biblioteca de Participantes', ar: 'مكتبة المشاركين', hi: 'प्रतिभागी पुस्तकालय', ru: 'Библиотека участников', it: 'Libreria Partecipanti' },
  'participantLibrary.subtitle': { en: 'Find participants for your research or get discovered by researchers.', zh: '为您的研究寻找参与者，或被研究人员发现。', es: 'Encuentra participantes para tu investigación o deja que los investigadores te descubran.', fr: 'Trouvez des participants pour votre recherche ou faites-vous découvrir par des chercheurs.', de: 'Finden Sie Teilnehmer für Ihre Forschung oder lassen Sie sich von Forschern entdecken.', ja: '研究の参加者を探すか、研究者に発見してもらいましょう。', ko: '연구를 위한 참여자를 찾거나 연구자에게 발견되세요.', pt: 'Encontre participantes para sua pesquisa ou seja descoberto por pesquisadores.', ar: 'ابحث عن مشاركين لبحثك أو اجعل الباحثين يكتشفونك.', hi: 'अपने शोध के लिए प्रतिभागी खोजें या शोधकर्ताओं द्वारा खोजे जाएं।', ru: 'Найдите участников для исследования или будьте найдены исследователями.', it: 'Trova partecipanti per la tua ricerca o fatti scoprire dai ricercatori.' },
  'participantLibrary.joinToggle': { en: 'Join Participant Library', zh: '加入参与者库', es: 'Unirse a la Biblioteca', fr: 'Rejoindre la Bibliothèque', de: 'Teilnehmerbibliothek beitreten', ja: '参加者ライブラリに参加', ko: '참여자 라이브러리 참여', pt: 'Entrar na Biblioteca', ar: 'الانضمام إلى مكتبة المشاركين', hi: 'प्रतिभागी पुस्तकालय में शामिल हों', ru: 'Присоединиться к библиотеке', it: 'Unisciti alla Libreria' },
  'participantLibrary.joinDesc': { en: 'Make your profile visible to researchers looking for participants.', zh: '让研究人员可以找到您的个人资料。', es: 'Haz tu perfil visible para investigadores que buscan participantes.', fr: 'Rendez votre profil visible aux chercheurs qui cherchent des participants.', de: 'Machen Sie Ihr Profil für Forscher sichtbar.', ja: '参加者を探している研究者にプロフィールを公開します。', ko: '참여자를 찾는 연구자에게 프로필을 공개하세요.', pt: 'Torne seu perfil visível para pesquisadores procurando participantes.', ar: 'اجعل ملفك الشخصي مرئيًا للباحثين الذين يبحثون عن مشاركين.', hi: 'प्रतिभागियों की तलाश कर रहे शोधकर्ताओं को अपनी प्रोफ़ाइल दिखाएं।', ru: 'Сделайте свой профиль видимым для исследователей.', it: 'Rendi il tuo profilo visibile ai ricercatori.' },
